**Parent Phase:** coding_agent_session_search-6uo3 (Phase 1: Core Export)
**Estimated Duration:** 2-3 days

## Goal

Define and implement the target SQLite schema optimized for browser consumption with sqlite-wasm, including indexes, materialized views, and metadata tables.

## Technical Approach

### Target Schema (`src/pages/schema.sql`)

```sql
-- Core tables
CREATE TABLE conversations (
    id INTEGER PRIMARY KEY,
    agent TEXT NOT NULL,
    workspace TEXT,
    title TEXT,
    source_path TEXT NOT NULL,
    started_at INTEGER,  -- Unix timestamp ms
    ended_at INTEGER,
    message_count INTEGER,
    metadata_json TEXT   -- Extensible JSON blob
);

CREATE TABLE messages (
    id INTEGER PRIMARY KEY,
    conversation_id INTEGER NOT NULL,
    idx INTEGER NOT NULL,
    role TEXT NOT NULL,    -- 'user', 'assistant', 'tool', 'system'
    content TEXT NOT NULL,
    created_at INTEGER,    -- Unix timestamp ms
    attachment_refs TEXT,  -- JSON array: ["sha256-abc...", ...]
    FOREIGN KEY (conversation_id) REFERENCES conversations(id)
);

-- Optional: Attachment metadata (--include-attachments)
CREATE TABLE IF NOT EXISTS attachments (
    hash TEXT PRIMARY KEY,       -- sha256 of plaintext
    filename TEXT NOT NULL,
    mime_type TEXT NOT NULL,
    size_bytes INTEGER NOT NULL,
    message_id INTEGER,
    created_at INTEGER,
    FOREIGN KEY (message_id) REFERENCES messages(id)
);

-- Indexes for common query patterns
CREATE INDEX idx_messages_conversation ON messages(conversation_id);
CREATE INDEX idx_messages_role ON messages(role);
CREATE INDEX idx_conversations_agent ON conversations(agent);
CREATE INDEX idx_conversations_workspace ON conversations(workspace);
CREATE INDEX idx_conversations_started ON conversations(started_at);

-- Export metadata
CREATE TABLE export_meta (
    key TEXT PRIMARY KEY,
    value TEXT
);
```

### Materialized Views for Performance

```sql
-- Recent conversations per agent (top 50)
CREATE TABLE mv_recent_by_agent AS
SELECT agent, conversation_id, title, started_at, message_count, rank
FROM (
    SELECT agent, id AS conversation_id, title, started_at, message_count,
           ROW_NUMBER() OVER (PARTITION BY agent ORDER BY started_at DESC) as rank
    FROM conversations
)
WHERE rank <= 50;

CREATE INDEX idx_mv_recent_agent ON mv_recent_by_agent(agent, rank);

-- Message snippets for fast search result preview
CREATE TABLE mv_message_snippets AS
SELECT id, conversation_id, role,
       SUBSTR(content, 1, 200) AS snippet,
       LENGTH(content) AS full_length
FROM messages;

CREATE INDEX idx_mv_snippets_conv ON mv_message_snippets(conversation_id);
```

### Why These Choices

- **INTEGER timestamps**: More compact than ISO strings, sqlite-wasm handles well
- **metadata_json**: Extensible without schema changes
- **Materialized views**: Trade 10-15% size increase for faster dashboard rendering
- **Message snippets**: Avoid loading full content for search results

### Schema Migration Support

```rust
pub fn create_export_database(path: &Path) -> Result<Connection> {
    let conn = Connection::open(path)?;
    conn.execute_batch(include_str!("schema.sql"))?;
    Ok(conn)
}
```

